INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "ジュエルを食べ物…\nいえ、貴重品と交換できます！", 1, 0, -363.0, 10001, 0.0, 1, 1, 0, 0.0, "ペコリーヌ", 105801, 10, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", 1, 0, -363.0, 10002, 0.0, 1, 1, 0, 0.0, "キャル", 106001, 10, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", 1, 0, -363.0, 10003, 0.0, 1, 1, 0, 0.0, "コッコロ", 105901, 10, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", 2, 0, -363.0, 10004, 0.0, 1, 1, 2104010, 0.0, "シェフィ", 106401, 10, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", 1, 0, -416.5, 12001, 0.0, 1, 1, 0, 0.0, "ペコリーヌ", 105801, 12, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", 1, 0, -363.0, 13001, 0.0, 1, 1, 0, 0.0, "キャル", 106001, 13, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", 1, 0, -363.0, 13002, 0.0, 1, 1, 0, 0.0, "コッコロ", 105901, 13, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", 2, 0, -363.0, 13003, 0.0, 1, 1, 2104010, 0.0, "シェフィ", 106401, 13, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", 1, 0, -363.0, 13004, 0.0, 1, 1, 0, 0.0, "ペコリーヌ", 105801, 13, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", 1, 0, -363.0, 14001, 0.0, 1, 1, 0, 0.0, "コッコロ", 105901, 14, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", 2, 0, -363.0, 14002, 0.0, 1, 1, 2104010, 0.0, "シェフィ", 106401, 14, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", 1, 0, -363.0, 14003, 0.0, 1, 1, 0, 0.0, "ペコリーヌ", 105801, 14, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", 1, 0, -363.0, 14004, 0.0, 1, 1, 0, 0.0, "キャル", 106001, 14, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", 1, 0, -470.0, 15001, 0.0, 1, 1, 0, 0.0, "コッコロ", 105901, 15, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", 2, 0, -363.0, 16001, 0.0, 1, 1, 2104010, 0.0, "シェフィ", 106401, 16, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", 1, 0, -363.0, 16002, 0.0, 1, 1, 0, 0.0, "ペコリーヌ", 105801, 16, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", 1, 0, -363.0, 16003, 0.0, 1, 1, 0, 0.0, "キャル", 106001, 16, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", 1, 0, -363.0, 16004, 0.0, 1, 1, 0, 0.0, "コッコロ", 105901, 16, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", 1, 0, -363.0, 17002, 0.0, 1, 1, 0, 0.0, "コッコロ", 105901, 17, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", 1, 0, -363.0, 17004, 0.0, 1, 1, 0, 0.0, "キャル", 106001, 25, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", 1, 0, -363.0, 17005, 0.0, 1, 1, 0, 0.0, "コッコロ", 105901, 25, "2030/12/17 14:59:59");
