INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", 1, 0, -470.0, 20001, 0.0, 5, 1, 0, 0.0, "カリン", 190801, 20, "2030/12/17 14:59:59");
