INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", 1, 0, -363.0, 21001, 0.0, 1, 1, 0, 0.0, "キャル", 106001, 21, "2030/12/17 14:59:59");
