INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", 1, 0, -430.0, 22001, 0.0, 1, 1, 0, 0.0, "カリン", 190801, 22, "2030/12/17 14:59:59");
