INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", 1, 0, -430.0, 23002, 0.0, 4, 1, 0, 0.0, "カリン", 190801, 23, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", 1, 10011, -385.0, 24001, 4.08, 1, 2, 0, 8.0, "エリコ（バレンタイン）", 109001, 24, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", 1, 10011, -385.0, 24002, 5.0, 2, 2, 0, 8.0, "エリコ（バレンタイン）", 109001, 24, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", 1, 10011, -385.0, 24003, 10.11, 3, 2, 0, 8.0, "エリコ（バレンタイン）", 109001, 24, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", 1, 10011, -385.0, 24004, 4.0, 4, 2, 0, 8.0, "エリコ（バレンタイン）", 109001, 24, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", 1, 10011, -385.0, 24005, 6.0, 5, 2, 0, 8.0, "エリコ（バレンタイン）", 109001, 24, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", 1, 10011, 0.0, 24006, 0.0, 6, 1, 0, 0.0, "エリコ（バレンタイン）", 109002, 24, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", 1, 10011, 0.0, 24007, 0.0, 7, 1, 0, 0.0, "エリコ（バレンタイン）", 109002, 24, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", 1, 10011, 0.0, 24008, 0.0, 8, 1, 0, 0.0, "エリコ（バレンタイン）", 109002, 24, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", 1, 10011, 0.0, 24009, 0.0, 9, 1, 0, 0.0, "エリコ（バレンタイン）", 109002, 24, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", 1, 10011, 0.0, 24010, 0.0, 10, 1, 0, 0.0, "エリコ（バレンタイン）", 109002, 24, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", 1, 10011, -385.0, 24011, 2.12, 1, 2, 0, 8.0, "シズル（バレンタイン）", 109101, 24, "2030/12/17 14:59:59");
