INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", 1, 10011, -385.0, 24017, 5.01, 7, 2, 0, 8.0, "シズル（バレンタイン）", 109101, 24, "2030/12/17 14:59:59");
