INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2019/01/31 12:00:00", "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", 1, 10011, 0.0, 24019, 0.0, 9, 1, 0, 0.0, "シズル（バレンタイン）", 109102, 24, "2030/12/17 14:59:59");
