INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", 1, 0, -363.0, 43003, 0.0, 1, 1, 0, 0.0, "キャル", 106001, 43, "2030/12/17 14:59:59");
