INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", 1, 0, -416.5, 43005, 0.0, 2, 1, 0, 0.0, "アメス", 123001, 44, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", 1, 0, -416.5, 43006, 5.79, 3, 2, 0, 0.0, "アメス", 123001, 45, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", 1, 0, -371.5, 46001, 0.0, 1, 1, 0, 0.0, "アメス", 123001, 46, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", 2, 0, -416.5, 47001, 0.0, 1, 2, 0, 0.0, "シズル", 104901, 47, "2030/12/17 14:59:59");
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES ("2015/12/17 15:00:00", "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", 1, 0, -416.5, 47002, 9.32, 1, 2, 0, 0.0, "リノ", 101101, 47, "2030/12/17 14:59:59");
